export const Emoji = {
    elements: {},
    filteredEmojis: [...STICKER_EMOJIS],
    
    init() {
        this.cacheElements();
        this.render();
        this.bindEvents();
        this.bindStateEvents();
    },
    
    cacheElements() {
        this.elements = {
            btn: document.getElementById('emojiBtn'),
            picker: document.getElementById('emojiPicker'),
            search: document.getElementById('emojiSearch'),
            grid: document.getElementById('emojiGrid')
        };
    },
    
    render() {
        this.elements.grid.innerHTML = this.filteredEmojis.map(emoji =>
            `<span class="emoji">${emoji}</span>`
        ).join('');
    },
    
    bindEvents() {
        this.elements.btn.addEventListener('click', (e) => {
            e.stopPropagation();
            State.toggleEmojiPicker();
        });
        
        this.elements.grid.addEventListener('click', (e) => {
            if (e.target.classList.contains('emoji')) {
                Input.insertEmoji(e.target.textContent);
                State.closeEmojiPicker();
            }
        });
        
        this.elements.search.addEventListener('input', (e) => {
            const query = e.target.value.toLowerCase();
            if (!query) {
                this.filteredEmojis = [...STICKER_EMOJIS];
            } else {
                this.filteredEmojis = STICKER_EMOJIS.filter(emoji => 
                    emoji.includes(query)
                );
            }
            this.render();
        });
        
        document.addEventListener('click', (e) => {
            if (!this.elements.picker.contains(e.target) &&
                !this.elements.btn.contains(e.target)) {
                State.closeEmojiPicker();
            }
        });
    },
    
    bindStateEvents() {
        State.subscribe((event, data) => {
            if (event === 'emojiToggle') {
                this.elements.picker.classList.toggle('active', data);
                if (data && this.elements.search) {
                    this.elements.search.value = '';
                    this.filteredEmojis = [...STICKER_EMOJIS];
                    this.render();
                    this.elements.search.focus();
                }
            } else if (event === 'emojiClosed') {
                this.elements.picker.classList.remove('active');
            }
        });
    }
};
